import React, { useState, useEffect, useCallback } from 'react';
import { pedidosIniciales, productosIniciales, clientesIniciales, estadoConfig } from './datos';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Pedidos from './components/Pedidos';
import Productos from './components/Productos';
import Clientes from './components/Clientes';
import Reportes from './components/Reportes';

const nombresDemo = ['Juan Pérez','Sofía Ramos','Diego Lima','Carla Montaño','Marco Ávila'];
const tiposDemo = ['🍔 Comida','💊 Farmacia','🛒 Tienda'];

function tocarCampana() {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain); gain.connect(ctx.destination);
    osc.frequency.value = 880;
    gain.gain.setValueAtTime(0.3, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime+0.8);
    osc.start(); osc.stop(ctx.currentTime+0.8);
  } catch(e){}
}

export default function App() {
  const [pagina, setPagina] = useState('dashboard');
  const [pedidos, setPedidos] = useState(pedidosIniciales);
  const [productos, setProductos] = useState(productosIniciales);
  const [notif, setNotif] = useState(null);

  const pedidosNuevos = pedidos.filter(p=>p.estado==='nuevo').length;

  const cambiarEstado = useCallback((id, nuevoEstado) => {
    setPedidos(prev => prev.map(p => p.id===id ? {...p, estado:nuevoEstado} : p));
  }, []);

  useEffect(() => {
    const intervalo = setInterval(() => {
      const nombre = nombresDemo[Math.floor(Math.random()*nombresDemo.length)];
      const tipo = tiposDemo[Math.floor(Math.random()*tiposDemo.length)];
      const nuevoPedido = {
        id: `#0${Math.floor(Math.random()*900)+100}`,
        cliente: nombre,
        telefono: `7${Math.floor(Math.random()*9000000)+1000000}`,
        direccion: `Calle ${Math.floor(Math.random()*900)+100}`,
        tipo, productos:[{ nombre:'Producto ejemplo', cant:1, precio:50 }],
        estado:'nuevo',
        hora: new Date().toLocaleTimeString('es-BO',{hour:'2-digit',minute:'2-digit'})
      };
      setPedidos(prev => [nuevoPedido, ...prev]);
      setNotif(`Nuevo pedido de ${nombre}`);
      tocarCampana();
      setTimeout(()=>setNotif(null), 4000);
    }, 30000);
    return () => clearInterval(intervalo);
  }, []);

  return (
    <div style={{ display:'flex', minHeight:'100vh' }}>
      <Sidebar pagina={pagina} setPagina={setPagina} pedidosNuevos={pedidosNuevos} />
      <main style={{ flex:1, overflowY:'auto', background:'#F1F5F9' }}>
        {pagina==='dashboard'  && <Dashboard pedidos={pedidos} setPagina={setPagina} />}
        {pagina==='pedidos'    && <Pedidos pedidos={pedidos} onCambiarEstado={cambiarEstado} />}
        {pagina==='productos'  && <Productos productos={productos} setProductos={setProductos} />}
        {pagina==='clientes'   && <Clientes clientes={clientesIniciales} />}
        {pagina==='reportes'   && <Reportes pedidos={pedidos} productos={productos} />}
        {pagina==='config'     && (
          <div style={{ padding:'1.5rem' }}>
            <h1 style={{ fontSize:20, fontWeight:700, marginBottom:'1rem' }}>Configuración</h1>
            <div style={{ background:'#fff', borderRadius:12, padding:'1.25rem', maxWidth:480 }}>
              <div style={{ fontWeight:600, marginBottom:'1rem' }}>Datos del negocio</div>
              {[['Nombre del negocio','PedidosFácil Demo'],['Teléfono','71234567'],['Dirección','La Paz, Bolivia'],['Horario','8:00 - 22:00']].map(([l,v])=>(
                <div key={l} style={{ marginBottom:'0.75rem' }}>
                  <label style={{ fontSize:13, color:'#64748B', display:'block', marginBottom:4 }}>{l}</label>
                  <input defaultValue={v} style={{ width:'100%', padding:'8px 12px', borderRadius:8, border:'1px solid #E2E8F0', fontSize:14, outline:'none' }} />
                </div>
              ))}
              <button style={{ marginTop:'0.5rem', padding:'8px 20px', borderRadius:8, border:'none', background:'#2563EB', color:'#fff', fontWeight:600, cursor:'pointer', fontSize:14 }}>
                Guardar cambios
              </button>
            </div>
          </div>
        )}
      </main>

      {notif && (
        <div style={{ position:'fixed', top:20, right:20, background:'#1E293B', color:'#fff', padding:'12px 20px', borderRadius:12, fontSize:14, fontWeight:500, zIndex:9999, display:'flex', alignItems:'center', gap:10 }}>
          🔔 {notif}
        </div>
      )}
    </div>
  );
}
